@startuml
title <u>UTIL's Class Diagram</u>

skinparam shadowing false
skinparam packageStyle rectangle
skinparam classAttributeIconSize 0

package "Twitter" {
  package "Util" {

    interface AccessModifiers {
      + value()
    }

    interface Attributes {
      + value()
    }

    interface Constructor {
      + value()
    }

    class MessageHandler {
      + messageHandler : MessageHandler
      # fadeIn : FadeTransition
      # fadeOut : FadeTransition
      --
      + getMessageHandler()
      - initTransitions()
      + displayMessage()
    }

    interface Methods {
      + value()
    }

    interface Singleton {
      + value()
    }

    interface WindowSizer {
      + anchorSize()
    }

    AccessModifiers -[hidden]- Attributes
    Attributes -[hidden]- Constructor

    MessageHandler -[hidden]- Methods
    Methods -[hidden]- Singleton

    MessageHandler -[hidden]- WindowSizer
  }
}
@enduml
